    const opportunity = portfolioOperatingModel.getMarketOpportunity(aggregatedOpportunityId);
    const urgency = opportunity.signals?.serviceUrgency;
    assert(urgency, 'expected signals.serviceUrgency');
    assert.equal(urgency.urgencyClass, 'emergency_first',
      `expected emergency_first, got ${urgency.urgencyClass} with scores ${JSON.stringify(urgency.classScores)}`);
    assert.equal(urgency.responseExpectationMinutes, 60);
    assert.equal(urgency.source, 'lead_evidence_service_urgency_detection');
    assert(Array.isArray(urgency.urgencyKeywords) && urgency.urgencyKeywords.length >= 2);
    assert(urgency.urgencyKeywords.some((kw) => /emergency|no heat|no ac|leak|midnight/.test(kw)),
      `expected urgency keywords to include an emergency term, got ${urgency.urgencyKeywords.join(', ')}`);
    assert(Array.isArray(urgency.responseRequirements)
      && urgency.responseRequirements.includes('after_hours_coverage_evidence'));
