  await check('portfolio.lead_evidence_detects_ad_saturation_and_offer_fatigue', () => {
    const opportunity = portfolioOperatingModel.getMarketOpportunity(aggregatedOpportunityId);
    const fatigue = opportunity.signals?.adSaturationOfferFatigue;
    assert(fatigue, 'expected signals.adSaturationOfferFatigue');
    assert.equal(fatigue.source, 'lead_evidence_ad_saturation_offer_fatigue_detection');
    assert(['elevated', 'high'].includes(fatigue.saturationLevel),
      `expected elevated/high ad saturation, got ${fatigue.saturationLevel}`);
    assert(['elevated', 'high'].includes(fatigue.fatigueLevel),
      `expected elevated/high offer fatigue, got ${fatigue.fatigueLevel}`);
    assert(Number.isFinite(fatigue.compositeScore) && fatigue.compositeScore >= 0.45);
    assert(Array.isArray(fatigue.signals) && fatigue.signals.length >= 3,
      `expected ad/fatigue signals, got ${JSON.stringify(fatigue.signals)}`);
    const signalKeys = fatigue.signals.map((entry) => entry.key);
    assert(signalKeys.includes('paid_ad_density'), `expected paid_ad_density, got ${signalKeys.join(', ')}`);
    assert(signalKeys.includes('discount_offer_fatigue'), `expected discount_offer_fatigue`);
    assert(signalKeys.includes('aggregator_crowding'), `expected aggregator_crowding`);
    assert(fatigue.saturationSignalKeys.includes('paid_ad_density'));
    assert(fatigue.fatigueSignalKeys.includes('discount_offer_fatigue'));
    assert(Array.isArray(fatigue.evidenceLeadIds)
      && fatigue.evidenceLeadIds.includes('lead:maygoals_lead_hvac_1')
      && fatigue.evidenceLeadIds.includes('lead:maygoals_lead_hvac_2'));
    assert(fatigue.recommendedPositioning);
    assert(fatigue.channelGuidance);
    assert(fatigue.assumptions.some((entry) => /no live ad-library/i.test(entry)));
    assert.equal(opportunity.risks.adSaturationLevel, fatigue.saturationLevel);
    assert.equal(opportunity.risks.offerFatigueLevel, fatigue.fatigueLevel);
    assert.equal(opportunity.risks.adSaturationCompositeScore, fatigue.compositeScore);
    assert.equal(
      opportunity.signals.confidenceIntervals.adSaturationOfferFatigue.compositeScore.point,
      fatigue.compositeScore
    );
    assert.equal(
      opportunity.signals.confidenceIntervals.adSaturationOfferFatigue.saturationScore.point,
      fatigue.saturationScore
    );
    assert.equal(
      opportunity.signals.confidenceIntervals.adSaturationOfferFatigue.fatigueScore.point,
      fatigue.fatigueScore
    );
  });

  await check('portfolio.market_claims_carry_confidence_intervals', () => {
    const opportunity = portfolioOperatingModel.getMarketOpportunity(aggregatedOpportunityId);
    const intervals = opportunity.signals?.confidenceIntervals;
    assert(intervals, 'expected signals.confidenceIntervals');
    assert.equal(intervals.source, 'lead_evidence_confidence_interval_propagation');
    assert.equal(intervals.summary.source, 'lead_evidence_confidence_interval_propagation');
    assert(['tight', 'measured', 'wide', 'speculative'].includes(intervals.summary.widthClass));
    assert.equal(intervals.summary.sampleSize, 3);
    assert.equal(intervals.summary.evidenceCount, 3);
    assert(Number.isFinite(intervals.summary.inputsAgreementScore)
      && intervals.summary.inputsAgreementScore > 0
      && intervals.summary.inputsAgreementScore <= 1);

    for (const interval of [
      intervals.score,
      intervals.confidence,
      intervals.exploitableWeaknessRatio,
      intervals.demandPressure.pressureScore,
      intervals.ownerResponsiveness.responseFrictionScore,
      intervals.reviewComplaintClusters.coveredLeadRatio,
      intervals.reviewComplaintClusters.topClusterScore,
      intervals.formationPermitSignals.coveredLeadRatio,
      intervals.formationPermitSignals.regulatoryRiskScore,
      intervals.localSeasonality.seasonalPressureScore,
      intervals.adSaturationOfferFatigue.compositeScore,
      intervals.adSaturationOfferFatigue.saturationScore,
      intervals.adSaturationOfferFatigue.fatigueScore,
      intervals.cityDemandMap.mappedLeadRatio,
      intervals.cityDemandMap.topHotspotScore,
      intervals.pricingMarginInference.confidence,
      intervals.pricingMarginInference.observedPriceSpreadRatio,
      intervals.neighborhoodLaunchPlan.priorityScore,
      intervals.marketRecommendationProvenance.explainabilityScore
    ]) {
      assert(Number.isFinite(interval.low) && Number.isFinite(interval.point) && Number.isFinite(interval.high));
      assert(interval.low <= interval.point && interval.point <= interval.high, JSON.stringify(interval));
      assert(['tight', 'measured', 'wide', 'speculative'].includes(interval.widthClass));
      assert.equal(interval.sampleSize, 3);
    }

    assert.equal(intervals.score.point, Number(opportunity.score.toFixed(4)));
    assert.equal(intervals.marketSizing.serviceableAvailableMarketCents.point,
      opportunity.signals.marketSizing.serviceableAvailableMarketCents);
    assert(intervals.marketSizing.serviceableAvailableMarketCents.low
      <= intervals.marketSizing.serviceableAvailableMarketCents.point);
    assert(intervals.marketSizing.serviceableAvailableMarketCents.high
      >= intervals.marketSizing.serviceableAvailableMarketCents.point);
    assert.equal(opportunity.risks.confidenceIntervalWidthClass, intervals.summary.widthClass);
    assert.equal(opportunity.risks.confidenceIntervalSpeculative, intervals.summary.speculative);
    assert.equal(opportunity.risks.claimConfidenceFloor, intervals.summary.minRatioLow);

    const speculative = buildMarketConfidenceIntervals({
      score: 0.8,
      confidence: 0.4,
      leadCount: 1,
      evidenceCount: 1,
      avgConfidence: 0.35,
      density: 0.2,
      exploitableWeaknessRatio: 1,
      demandPressure: { pressureScore: 0.7 },
      marketSizing: {
        confidence: 0.35,
        estimatedCallableRevenueCents: 60000,
        serviceableAvailableMarketCents: 60000,
        obtainableFirstWaveCents: 0
      },
      ownerResponsiveness: { responseFrictionScore: 0.8 }
    });
    assert.equal(speculative.summary.widthClass, 'speculative');
    const tighter = buildMarketConfidenceIntervals({
      score: 0.8,
      confidence: 0.9,
      leadCount: 8,
      evidenceCount: 8,
      avgConfidence: 0.9,
      density: 1,
      exploitableWeaknessRatio: 0.75,
      demandPressure: { pressureScore: 0.65 },
      marketSizing: {
        confidence: 0.9,
        estimatedCallableRevenueCents: 480000,
        serviceableAvailableMarketCents: 480000,
        obtainableFirstWaveCents: 180000
      },
      ownerResponsiveness: { responseFrictionScore: 0.2 }
    });
    assert(tighter.score.halfWidth < speculative.score.halfWidth,
      `expected more evidence to narrow interval: ${tighter.score.halfWidth} !< ${speculative.score.halfWidth}`);
    assert(['tight', 'measured'].includes(tighter.score.widthClass));
  });

