  await check('portfolio.eval_live_adapter_contract_artifact_is_executable_and_ci_wired', () => {
    const packageJson = JSON.parse(readFileSync(join(process.cwd(), 'package.json'), 'utf8'));
    assert.equal(
      packageJson.scripts['check:eval-adapter-contract'],
      'node scripts/generated-evals/operator_handoff_customer_success.check.js'
    );
    assert.equal(
      packageJson.scripts['check:ci'],
      'npm run check && npm run check:evals && npm run check:handoff && npm run check:eval-adapter-contract && npm run check:maygoals'
    );
    const generatedEvalPath = join(process.cwd(), 'scripts/generated-evals/operator_handoff_customer_success.check.js');
    const generatedEvalSource = readFileSync(generatedEvalPath, 'utf8');
    assert(generatedEvalSource.includes('runOperatorHandoffEvalLiveAdapterContract'));
    assert(generatedEvalSource.includes('externalProvidersCalled'));
    assert(generatedEvalSource.includes('databaseWritesRequired'));
    assert(generatedEvalSource.includes('liveSideEffects'));
    assert(generatedEvalSource.includes('legal'));
    assert(generatedEvalSource.includes('refund_threat'));

    const workflowSource = readFileSync(join(process.cwd(), '.github/workflows/callan-evals.yml'), 'utf8');
    for (const token of [
      'pull_request:',
      'workflow_dispatch:',
      'npm ci',
      'npm run check',
      'npm run check:evals',
      'npm run check:handoff',
      'npm run check:eval-adapter-contract',
      'npm run check:maygoals',
      'LIVE_CALLS: "false"',
      'LIVE_EMAILS: "false"',
      'LIVE_PAYMENTS: "false"',
      'LIVE_PUBLIC_OUTREACH: "false"'
    ]) {
      assert(workflowSource.includes(token), `expected CI workflow token ${token}`);
    }

    const run = spawnSync(process.execPath, [generatedEvalPath], {
      cwd: process.cwd(),
      env: {
        ...process.env,
        NODE_ENV: 'test',
        RUN_MODE: 'mock',
        LIVE_CALLS: 'false',
        LIVE_EMAILS: 'false',
        LIVE_PAYMENTS: 'false',
        LIVE_BROWSER_SESSIONS: 'false',
        LIVE_PUBLIC_OUTREACH: 'false',
        LIVE_BUILDS: 'false'
      },
      encoding: 'utf8',
      timeout: 20_000,
      maxBuffer: 1024 * 1024
    });
    if (run.error) throw run.error;
    assert.equal(run.status, 0, `generated adapter contract eval failed: ${run.stderr || run.stdout}`);
    const payload = JSON.parse(run.stdout);
    assert.equal(payload.ok, true);
    assert.equal(payload.name, 'operator-handoff-live-adapter-contract');
    assert.equal(payload.summary.total, 5);
    assert.equal(payload.summary.passed, 5);
    assert.equal(payload.summary.failed, 0);
    assert.equal(payload.summary.inProcessOnly, true);
    assert.equal(payload.summary.nonMutating, true);
    assert.equal(payload.summary.externalProvidersCalled, false);
    assert.equal(payload.summary.databaseWritesRequired, false);
    assert.equal(payload.summary.liveSideEffects, false);
    assert(payload.cases.some((item) => item.expectedCategory === 'legal' && item.observedCategory === 'legal'));
    assert(payload.cases.some((item) => item.expectedCategory === 'refund_threat' && item.observedCategory === 'refund_threat'));
  });

