  await check('portfolio.market_false_positive_learning_reduces_repeat_launch_recommendation', () => {
    const before = portfolioOperatingModel.getMarketOpportunity(aggregatedOpportunityId);
    assert.equal(before.decision, 'launch_candidate');
    const outcome = recordMarketRecommendationOutcome({
      opportunityId: aggregatedOpportunityId,
      outcome: 'false_positive',
      reasonKey: 'launch_candidate_failed_operator_review',
      summary: 'Tempe HVAC looked launchable from lead evidence, but operator review found the first market recommendation was a false positive until fresh proof exists.',
      evidence: [
        {
          source: 'maygoals-check',
          id: 'tempe-hvac-false-positive-review',
          summary: 'Operator review rejected repeat launch because the market evidence overstated readiness.'
        }
      ],
      observedAt: mayGoalsNow + 60_000,
      now: mayGoalsNow + 60_000
    });
    assert.equal(outcome.ok, true);
    assert.equal(outcome.learning.state, 'false_positive_observed');
    assert.equal(outcome.learning.falsePositiveCount, 1);
    assert.equal(outcome.learning.recommendedDecision, 'watch');
    assert(outcome.learning.scorePenalty > 0);
    assert(outcome.learning.reasonKeys.includes('launch_candidate_failed_operator_review'));
    assert.equal(outcome.opportunity.status, 'learning_review');
    assert.equal(outcome.opportunity.decision, 'watch');
    assert(outcome.opportunity.score < before.score);
    assert.equal(outcome.opportunity.risks.marketOutcomeLearningApplied, true);
    assert.equal(outcome.opportunity.risks.marketFalsePositiveCount, 1);
    assert.equal(outcome.opportunity.risks.learnedDecisionOverride, 'watch');
    assert.equal(outcome.learningRecord.kind, 'market_false_positive');
    assert.equal(outcome.learningRecord.source_type, 'market_opportunity_outcome');
    assert.equal(outcome.learningRecord.source_id, aggregatedOpportunityId);
    assert.equal(outcome.learningRecord.impact.revisedDecision, 'watch');

    const repeatedAggregation = aggregateLeadMarketOpportunities({
      workspaceId: workspace.id,
      minLeads: 2,
      limit: 10,
      now: mayGoalsNow + 120_000
    });
    assert.equal(repeatedAggregation.createdOrUpdated, 1);
    const repeated = repeatedAggregation.opportunities.find((entry) => entry.opportunity.id === aggregatedOpportunityId)?.opportunity;
    assert(repeated, 'expected repeated aggregation to preserve Tempe opportunity');
    assert.equal(repeated.decision, 'watch');
    assert.equal(repeated.signals.marketOutcomeLearning.appliedToFreshEvidence, true);
    assert.equal(repeated.signals.marketOutcomeLearning.appliedScorePenalty, outcome.learning.scorePenalty);
    assert(repeated.signals.marketOutcomeLearning.preLearningScore > repeated.signals.marketOutcomeLearning.postLearningScore);
    assert.equal(repeated.risks.marketRecommendationPenalty, outcome.learning.scorePenalty);
    assert.equal(repeated.risks.learnedDecisionOverride, 'watch');
  });

