		    assert.equal(unsafeProviderSmokeReceipt.body?.receipt?.live, false);
		    assert.equal(unsafeProviderSmokeReceipt.body?.receipt?.detail?.unsafeSideEffectClaimed, true);
		    assert.equal(unsafeProviderSmokeReceipt.body?.proofPacket?.providerHealthEventMatched, false);
		    assert.equal(unsafeProviderSmokeReceipt.body?.proofPacket?.checks?.providerCalledByCallan, true);
		    assert.equal(unsafeProviderSmokeReceipt.body?.proofPacket?.checks?.externalSideEffects, true);
		    assert.equal(unsafeProviderSmokeReceipt.body?.proofPacket?.checks?.jobEnqueued, true);
		    assert.equal(unsafeProviderSmokeReceipt.body?.proofPacket?.checks?.customerMessageSent, true);
		    assert.equal(unsafeProviderSmokeReceipt.body?.proofPacket?.checks?.unsafeSideEffectClaimed, true);
		    assert.equal(unsafeProviderSmokeReceipt.body?.proofPacket?.safety?.sideEffectClaimsRejected, true);
