async function verifyMergeQueueRuntimeSecretProviderSmokeExecutionGateRouteBoundary({ readinessReceiptId }) {
  assert(readinessReceiptId, 'expected seeded runtime secret-provider smoke readiness receipt id for route proof');
  const beforeSideEffects = {
    providerCredentials: dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_provider_credential_receipts`).get().n,
    liveAdapters: dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_live_adapter_receipts`).get().n,
    acquisitionReceipts: dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_acquisition_action_receipts`).get().n
  };
  const beforeReceiptCount = dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_eval_merge_queue_runtime_secret_provider_smoke_execution_gate_receipts`).get().n;
  const port = await openEphemeralPort();
  const baseUrl = `http://localhost:${port}`;
  const child = spawn(process.execPath, ['server/index.js'], {
    cwd: process.cwd(),
    env: {
      ...process.env,
      PORT: String(port),
      DATA_DIR: dataDir,
      RUN_MODE: 'mock',
      NODE_ENV: 'test',
      ADMIN_API_TOKEN: '',
      GITHUB_TOKEN: '',
      AUTONOMOUS_OUTREACH_ENABLED: 'false',
      ACCOUNT_MANAGER_ENABLED: 'false',
      AFTERCARE_ENABLED: 'false',
      OPS_BACKUP_ENABLED: 'false',
      OPS_PROVIDER_POSTURE_ENABLED: 'false',
      OPS_RECOVERY_ENABLED: 'false',
      RETENTION_COMMAND_LEASE_MAINTENANCE_ENABLED: 'false',
      SAFE_TO_SELL_SELF_CHECK_ENABLED: 'false',
      SAFE_TO_RENEW_SELF_CHECK_ENABLED: 'false',
      LIVE_CALLS: 'false',
      LIVE_EMAILS: 'false',
      LIVE_PAYMENTS: 'false',
      LIVE_BROWSER_SESSIONS: 'false',
      LIVE_BUILDS: 'false',
      LIVE_PUBLIC_OUTREACH: 'false'
    },
    stdio: ['ignore', 'pipe', 'pipe']
  });
  let childOutput = '';
  const capture = (chunk) => {
    childOutput += String(chunk);
    if (childOutput.length > 20_000) childOutput = childOutput.slice(-20_000);
  };
  child.stdout.on('data', capture);
  child.stderr.on('data', capture);

  try {
    await waitForRouteJson(`${baseUrl}/api/ping`, child, () => childOutput);
    const routeUrl = `${baseUrl}/api/portfolio/eval-merge-queue-runtime-secret-provider-smoke-readiness-receipts/${encodeURIComponent(readinessReceiptId)}/smoke-execution-gate`;
    const missing = await fetchRouteJson(`${baseUrl}/api/portfolio/eval-merge-queue-runtime-secret-provider-smoke-readiness-receipts/missing_runtime_secret_provider_smoke_readiness/smoke-execution-gate`, {
      method: 'POST',
      body: { evidence: [{ id: 'maygoals-route-missing-secret-smoke-readiness', source: 'maygoals-route-check' }] }
    });
    assert.equal(missing.status, 404);
    assert.match(missing.body?.error || '', /smoke readiness receipt not found/i);

    const liveMode = await fetchRouteJson(routeUrl, {
      method: 'POST',
      body: {
        mode: 'live',
        evidence: [{ id: 'maygoals-route-secret-smoke-live-mode-rejected', source: 'maygoals-route-check' }]
      }
    });
    assert.equal(liveMode.status, 400);
    assert.match(liveMode.body?.error || '', /dry_run\/local_review only/);

    const requestBody = {
      runtimeSecretRef: 'github_merge_queue_read_token',
      requestMethod: 'GET',
      releaseScope: 'single_github_ruleset_get',
      smokeProvider: 'github',
      smokeCommand: 'npm run smoke:provider -- --provider=github --secret-ref=github_merge_queue_read_token --live',
      blockedReasons: [
        'runtime_secret_value_access_disallowed',
        'token_release_requires_passed_smoke',
        'live_github_http_request_blocked'
      ],
      smokeExecutionChecklist: [
        'smoke_readiness_recorded',
        'operator_release_ack_recorded',
        'secret_access_blocked',
        'token_release_denied'
      ],
      liveHttpReleasePlan: [
        'run_successful_runtime_secret_provider_smoke',
        'release_runtime_token_memory_only',
        'perform_single_github_ruleset_get',
        'record_response_without_merge'
      ],
      evidence: [{ id: 'maygoals-route-secret-provider-smoke-execution-gate', source: 'maygoals-route-check' }]
    };
    const gate = await fetchRouteJson(routeUrl, { method: 'POST', body: requestBody });
    assert.equal(gate.status, 200);
    assert.equal(gate.body?.receipt?.status, 'merge_queue_runtime_secret_provider_smoke_execution_blocked_no_secret_access');
    assert.equal(gate.body?.receipt?.runtime_secret_provider_smoke_attempted, 0);
    assert.equal(gate.body?.receipt?.runtime_secret_provider_smoke_executed, 0);
    assert.equal(gate.body?.receipt?.runtime_secret_provider_smoke_passed, 0);
    assert.equal(gate.body?.receipt?.runtime_secret_value_observed, 0);
    assert.equal(gate.body?.receipt?.token_release_approved, 0);
    assert.equal(gate.body?.receipt?.authorization_header_materialized, 0);
    assert.equal(gate.body?.receipt?.http_request_sent, 0);
    assert.equal(gate.body?.receipt?.live_github_api_called, 0);
    assert.equal(gate.body?.receipt?.merge_executed, 0);
    assert(gate.body?.receipt?.response?.blockedReasons?.includes('runtime_secret_value_access_disallowed'));
    assert.equal(/ghp_|github_pat_|sk_live_|whsec_/.test(JSON.stringify(gate.body)), false);

    const retry = await fetchRouteJson(routeUrl, { method: 'POST', body: requestBody });
    assert.equal(retry.status, 200);
    assert.equal(retry.body?.receipt?.id, gate.body?.receipt?.id);

    const afterSideEffects = {
      providerCredentials: dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_provider_credential_receipts`).get().n,
      liveAdapters: dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_live_adapter_receipts`).get().n,
      acquisitionReceipts: dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_acquisition_action_receipts`).get().n
    };
    const afterReceiptCount = dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_eval_merge_queue_runtime_secret_provider_smoke_execution_gate_receipts`).get().n;
    return {
      missingStatus: missing.status,
      liveModeStatus: liveMode.status,
      liveModeRejected: /dry_run\/local_review only/.test(liveMode.body?.error || ''),
      gateStatus: gate.status,
      gateReceiptStatus: gate.body.receipt.status,
      gateReceiptMode: gate.body.receipt.mode,
      runtimeSecretProviderSmokeReadinessObserved: gate.body.receipt.runtime_secret_provider_smoke_readiness_observed,
      runtimeSecretProviderSmokeExecutionBlocked: gate.body.receipt.runtime_secret_provider_smoke_execution_blocked,
      runtimeSecretProviderSmokeAttempted: gate.body.receipt.runtime_secret_provider_smoke_attempted,
      runtimeSecretProviderSmokeExecuted: gate.body.receipt.runtime_secret_provider_smoke_executed,
      runtimeSecretProviderSmokePassed: gate.body.receipt.runtime_secret_provider_smoke_passed,
      runtimeSecretValueObserved: gate.body.receipt.runtime_secret_value_observed,
      tokenReleaseApproved: gate.body.receipt.token_release_approved,
      tokenReleased: gate.body.receipt.token_released,
      authorizationHeaderMaterialized: gate.body.receipt.authorization_header_materialized,
      httpRequestSent: gate.body.receipt.http_request_sent,
      liveGithubApiCalled: gate.body.receipt.live_github_api_called,
      mergeExecuted: gate.body.receipt.merge_executed,
      responseRuntimeSecretProviderSmokeExecutionBlocked: gate.body.receipt.response.runtimeSecretProviderSmokeExecutionBlocked,
      responseRuntimeSecretProviderSmokeAttempted: gate.body.receipt.response.runtimeSecretProviderSmokeAttempted,
      responseRuntimeSecretValueObserved: gate.body.receipt.response.runtimeSecretValueObserved,
      responseHttpRequestSent: gate.body.receipt.response.httpRequestSent,
      responseMergeExecuted: gate.body.receipt.response.mergeExecuted,
      blockedRuntimeSecretValueAccess: gate.body.receipt.response.blockedReasons.includes('runtime_secret_value_access_disallowed'),
      retryStatus: retry.status,
      retrySameReceipt: retry.body.receipt.id === gate.body.receipt.id,
      receiptCountDelta: afterReceiptCount - beforeReceiptCount,
      beforeSideEffects,
      afterSideEffects,
      redactionOk: /ghp_|github_pat_|sk_live_|whsec_/.test(JSON.stringify({ gate: gate.body, retry: retry.body })) === false
    };
  } catch (err) {
    err.message = `${err.message}\nmerge queue runtime secret-provider smoke execution route server output:\n${childOutput}`;
    throw err;
  } finally {
    await stopRouteChild(child);
  }
}

