    assert(exportedAudit.blockers.some((item) => item.code === 'post_attestation_release_escrow_held_by_final_blocker_ledger'));
    assert.equal(exported.body?.redaction?.manifest?.proofReceipts?.mergeQueueConsolidatedBlockerAudits, 1);
    assert.equal(exported.body?.redaction?.manifest?.receiptTables?.portfolioEvalMergeQueueConsolidatedBlockerAudits, 1);

