      planAmountBoundaryPaymentCents: plan.body.receipt.response.providerSafety?.amountBoundary?.paymentAmountCents,
      preflightUnauthorizedStatus: preflightUnauthorized.status,
      preflightStatus: preflight.status,
      preflightOk: preflight.body.ok,
      preflightReceiptMode: preflight.body.receipt.mode,
      preflightReceiptStatus: preflight.body.receipt.status,
      preflightExternalSideEffects: preflight.body.receipt.response.externalSideEffects,
      preflightHasRunModeBlocker: preflightBlockers.includes('run_mode'),
      preflightHasSideEffectBlocker: preflightBlockers.includes('side_effect_flag'),
      preflightHasLiveGuardrailBlocker: preflightBlockers.includes('live_refund_guardrail'),
      preflightHasCustomerIssueBlocker: preflightBlockers.includes('customer_issue_evidence'),
      preflightHasRefundPolicyBlocker: preflightBlockers.includes('refund_policy_evidence'),
      preflightHasDisputeHandoffBlocker: preflightBlockers.includes('dispute_handoff_evidence'),
      preflightHasVendorResolutionBlocker: preflightBlockers.includes('vendor_dispute_resolution_evidence'),
      preflightHasOperatorApprovalBlocker: preflightBlockers.includes('operator_refund_approval'),
