      dryRunPlaybookStatus: dryRun.body.playbook.status,
      preflightUnauthorizedStatus: preflightUnauthorized.status,
      preflightStatus: preflight.status,
      preflightReceiptMode: preflight.body.receipt.mode,
      preflightReceiptStatus: preflight.body.receipt.status,
      preflightHasRunModeBlocker: preflightBlockers.includes('run_mode'),
      preflightHasProviderSmokeBlocker: preflightBlockers.includes('provider_live_smoke'),
      preflightHasLiveAdapterBlocker: preflightBlockers.includes('live_adapter_implemented'),
      preflightHasDryRunBlocker: preflightBlockers.includes('dry_run_receipt'),
