      rollbackReceiptStatus: rollback.body.receipt.status,
      rollbackRestored: rollback.body.receipt.response.restored,
      rollbackCustomerMessageSent: rollback.body.receipt.response.customerMessageSent,
      rollbackPlaybookStatus: rollback.body.playbook.status,
      cohortUnauthorizedStatus: cohortUnauthorized.status,
