    const commandList = await fetchRouteJson(commandListUrl, { token: adminToken });
    assert.equal(commandList.status, 200);
    const commandDetail = await fetchRouteJson(`${baseUrl}/api/portfolio/retention-command-center/${encodeURIComponent(rollupSeed.id)}?${qs({ workspaceId: 'ws_callan', limit: 200 })}`, { token: adminToken });
