      planVendorReassigned: plan.body.receipt.response.executionPackage.vendorReassigned,
      planServiceShutdownChanged: plan.body.receipt.response.executionPackage.serviceShutdownChanged,
      planProviderCalled: plan.body.receipt.response.proofPacket.safety.providerCalled,
      preflightUnauthorizedStatus: preflightUnauthorized.status,
      preflightStatus: preflight.status,
      preflightReceiptMode: preflight.body.receipt.mode,
      preflightReceiptStatus: preflight.body.receipt.status,
      preflightHasRunModeBlocker: preflightBlockers.includes('run_mode'),
      preflightHasSideEffectBlocker: preflightBlockers.includes('side_effect_flag'),
      preflightHasBoardApprovalBlocker: preflightBlockers.includes('operator_board_approval'),
      preflightHasRetentionPreflightBlocker: preflightBlockers.includes('retention_playbook_live_preflight_ready'),
      preflightHasVendorQualityPreflightBlocker: preflightBlockers.includes('vendor_quality_live_preflight_ready'),
      preflightHasProviderSmokeBlocker: preflightBlockers.includes('provider_live_smoke'),
      preflightHasLiveAdapterBlocker: preflightBlockers.includes('live_adapter_implemented'),
      liveExecuteUnauthorizedStatus: liveExecuteUnauthorized.status,
      liveExecuteBlockedStatus: liveExecuteBlocked.status,
