    const afterServiceDecisionFusionCount = dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_service_decision_fusion_receipts WHERE workspace_id = ?`).get('ws_callan').n;
    const afterServiceDecisionExecutionCount = dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_service_decision_execution_receipts WHERE workspace_id = ?`).get('ws_callan').n;
