      reviewReceiptDelta: afterReviewReceiptCount - beforeReviewReceiptCount,
      liveReadinessEvidenceDelta: afterLiveReadinessEvidenceCount - beforeLiveReadinessEvidenceCount,
      liveAdapterReceiptDelta: afterLiveAdapterReceiptCount - beforeLiveAdapterReceiptCount,
      workflowCompensationPlanDelta: afterWorkflowCompensationPlanCount - beforeWorkflowCompensationPlanCount,
      workflowCompensationReceiptDelta: afterWorkflowCompensationReceiptCount - beforeWorkflowCompensationReceiptCount,
      readinessReconciliationDelta: afterReadinessReconciliationCount - beforeReadinessReconciliationCount,
      serviceDecisionExecutionDelta: afterServiceDecisionExecutionCount - beforeServiceDecisionExecutionCount,
      decisionDistributionDelta: afterDecisionDistributionCount - beforeDecisionDistributionCount,
      decisionWorkItemDelta: afterDecisionWorkItemCount - beforeDecisionWorkItemCount,
      decisionWorkItemReceiptDelta: afterDecisionWorkItemReceiptCount - beforeDecisionWorkItemReceiptCount,
      beforeSideEffects,
