      serviceDecisionReadinessReconciliations: dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_service_decision_readiness_reconciliations WHERE workspace_id = ?`).get('ws_callan').n,
      serviceDecisionExecutionReceipts: dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_service_decision_execution_receipts WHERE workspace_id = ?`).get('ws_callan').n,
      decisionDistributionReceipts: dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_decision_distribution_receipts WHERE workspace_id = ?`).get('ws_callan').n,
      decisionWorkItems: dbHandle.prepare(`SELECT COUNT(*) AS n FROM portfolio_decision_work_items WHERE workspace_id = ?`).get('ws_callan').n,
