      listContainsAdapterReview: listReceipts.some((item) => item.id === adapterReceipt.id),
      providerFilterStatus: providerFilter.status,
      providerFilterOnlyProviderSmoke: providerFilterReceipts.length === 1 && providerFilterReceipts.every((item) => item.proof_key === 'provider_live_smoke'),
      adapterBlockerFilterStatus: adapterBlockerFilter.status,
      adapterBlockerFilterOnlyAdapter: adapterFilterReceipts.length === 1 && adapterFilterReceipts.every((item) => item.proof_key === 'live_adapter_implemented'),
      reviewKindFilterStatus: reviewKindFilter.status,
      reviewKindFilterCount: reviewKindReceipts.length,
      statusFilterStatus: statusFilter.status,
      statusFilterCount: statusReceipts.length,
      providerNameFilterStatus: providerNameFilter.status,
      providerNameFilterCount: providerNameReceipts.length,
      detailUnauthorizedStatus: detailUnauthorized.status,
      detailStatus: detail.status,
      detailReadOnly: detail.body.readOnly,
      detailIdMatches: detailReceipt.id === providerReceipt.id,
      detailCommandMatches: detail.body.command?.id === seed.readiness_reconciliation_id,
      detailExecutionMatches: detail.body.execution?.id === seed.service_decision_execution_receipt_id,
      detailReconciliationBlocked: detail.body.reconciliation?.status === 'blocked',
      detailReadinessEvidenceCountAtLeastTwo: detail.body.readinessEvidenceCount >= 2,
      detailLiveAdapterReceiptCountAtLeastOne: detail.body.liveAdapterReceiptCount >= 1,
      detailLiveGateClearedByReview: detailResponse.liveGateClearedByReview,
      detailLocalReviewCanClearLiveGate: detailResponse.localReviewCanClearLiveGate,
