    const capture = (chunk) => {
      output += String(chunk);
      if (output.length > 20_000) output = output.slice(-20_000);
    };
    child.stdout.on('data', capture);
    child.stderr.on('data', capture);
    await waitForRouteJson(`http://localhost:${port}/api/ping`, child, () => output);
    return { child, output: () => output, baseUrl: `http://localhost:${port}` };
